            { "@type": "Question", "name": "\u0647\u0644 2\u060c000 \u062f\u0648\u0644\u0627\u0631 \u0633\u0639\u0631 \u0639\u0627\u062f\u0644 \u0644\u0645\u0633\u0627\u0639\u062f \u0648\u0627\u062a\u0633\u0627\u0628 \u0630\u0643\u064a \u0641\u064a \u0639\u064f\u0645\u0627\u0646\u061f", "acceptedAnswer": { "@type": "Answer", "text": "\u0646\u0639\u0645\u060c 2\u060c000 \u062f\u0648\u0644\u0627\u0631 \u0647\u0648 \u0627\u0644\u0633\u0639\u0631 \u0627\u0644\u0648\u0633\u0637\u064a \u0644\u0628\u0646\u0627\u0621 \u0645\u0633\u0627\u0639\u062f \u0648\u0627\u062a\u0633\u0627\u0628 \u0630\u0643\u064a \u0627\u062d\u062a\u0631\u0627\u0641\u064a \u0641\u064a \u0639\u064f\u0645\u0627\u0646." } },
            { "@type": "Question", "name": "\u0643\u0645 \u064a\u0633\u062a\u063a\u0631\u0642 \u0645\u0633\u0627\u0639\u062f \u0648\u0627\u062a\u0633\u0627\u0628 \u0627\u0644\u0630\u0643\u064a \u062d\u062a\u0649 \u064a\u0633\u062f\u062f \u062a\u0643\u0644\u0641\u062a\u0647\u061f", "acceptedAnswer": { "@type": "Answer", "text": "\u062a\u064f\u0641\u064a\u062f \u0645\u0639\u0638\u0645 \u0627\u0644\u0634\u0631\u0643\u0627\u062a \u0627\u0644\u0635\u063a\u064a\u0631\u0629 \u0648\u0627\u0644\u0645\u062a\u0648\u0633\u0637\u0629 \u0641\u064a \u0639\u064f\u0645\u0627\u0646 \u0628\u062a\u062d\u0642\u064a\u0642 \u0627\u0644\u062a\u0639\u0627\u062f\u0644 \u062e\u0644\u0627\u0644 6 \u0625\u0644\u0649 10 \u0623\u0633\u0627\u0628\u064a\u0639 \u0645\u0646 \u0627\u0644\u0646\u0634\u0631." } },
