            { "@type": "Question", "name": "\u0645\u0627 \u0627\u0644\u0641\u0631\u0642 \u0628\u064a\u0646 \u0631\u0648\u0628\u0648\u062a \u0648\u0627\u062a\u0633\u0627\u0628 \u0627\u0644\u0631\u062e\u064a\u0635 \u0648\u0645\u0633\u0627\u0639\u062f \u0630\u0643\u064a\u061f", "acceptedAnswer": { "@type": "Answer", "text": "\u064a\u0639\u062a\u0645\u062f \u0627\u0644\u0631\u0648\u0628\u0648\u062a \u0627\u0644\u0631\u062e\u064a\u0635 \u0639\u0644\u0649 \u0645\u0637\u0627\u0628\u0642\u0629 \u0627\u0644\u0643\u0644\u0645\u0627\u062a \u0627\u0644\u0645\u0641\u062a\u0627\u062d\u064a\u0629. \u0623\u0645\u0627 \u0627\u0644\u0645\u0633\u0627\u0639\u062f \u0627\u0644\u0630\u0643\u064a \u0641\u064a\u0633\u062a\u062e\u062f\u0645 \u0645\u0639\u0627\u0644\u062c\u0629 \u0627\u0644\u0644\u063a\u0629 \u0627\u0644\u0637\u0628\u064a\u0639\u064a\u0629 \u0648\u064a\u062a\u0643\u0627\u0645\u0644 \u0645\u0639 CRM." } },
            { "@type": "Question", "name": "\u0647\u0644 \u064a\u0639\u0645\u0644 \u0645\u0633\u0627\u0639\u062f \u0648\u0627\u062a\u0633\u0627\u0628 \u0627\u0644\u0630\u0643\u064a \u0645\u0639 \u0627\u0644\u0639\u0645\u0644\u0627\u0621 \u0627\u0644\u0646\u0627\u0637\u0642\u064a\u0646 \u0628\u0627\u0644\u0639\u0631\u0628\u064a\u0629\u061f", "acceptedAnswer": { "@type": "Answer", "text": "\u0646\u0639\u0645\u060c \u0644\u0643\u0646 \u0641\u0642\u0637 \u0625\u0630\u0627 \u0628\u064f\u0646\u064a \u0628\u0634\u0643\u0644 \u0635\u062d\u064a\u062d. \u064a\u062f\u0639\u0645 \u0627\u0644\u0646\u0638\u0627\u0645 \u0627\u0644\u0645\u064f\u0647\u064a\u0623 \u0635\u062d\u064a\u062d\u0627\u064b \u0627\u0644\u0639\u0631\u0628\u064a\u0629 \u0648\u0627\u0644\u0625\u0646\u062c\u0644\u064a\u0632\u064a\u0629." } },
            { "@type": "Question", "name": "\u0645\u0627 \u0627\u0644\u0631\u0633\u0648\u0645 \u0627\u0644\u0634\u0647\u0631\u064a\u0629 \u0627\u0644\u0645\u062a\u0648\u0642\u0639\u0629\u061f", "acceptedAnswer": { "@type": "Answer", "text": "\u062a\u0648\u0642\u0639 \u062a\u0643\u0627\u0644\u064a\u0641 \u0634\u0647\u0631\u064a\u0629 \u0645\u0633\u062a\u0645\u0631\u0629 \u062a\u062a\u0631\u0627\u0648\u062d \u0628\u064a\u0646 40 \u0648120 \u0631\u064a\u0627\u0644 \u0639\u064f\u0645\u0627\u0646\u064a." } },
            { "@type": "Question", "name": "\u0647\u0644 \u064a\u062a\u0648\u0627\u0641\u0642 \u0645\u0633\u0627\u0639\u062f \u0648\u0627\u062a\u0633\u0627\u0628 \u0627\u0644\u0630\u0643\u064a \u0645\u0639 \u0642\u0627\u0646\u0648\u0646 \u062d\u0645\u0627\u064a\u0629 \u0627\u0644\u0628\u064a\u0627\u0646\u0627\u062a \u0627\u0644\u0634\u062e\u0635\u064a\u0629 \u0627\u0644\u0639\u064f\u0645\u0627\u0646\u064a\u061f", "acceptedAnswer": { "@type": "Answer", "text": "\u064a\u0645\u0643\u0646 \u0630\u0644\u0643\u060c \u0644\u0643\u0646 \u064a\u062a\u0637\u0644\u0628 \u062a\u0635\u0645\u064a\u0645\u0627\u064b \u0645\u0642\u0635\u0648\u062f\u0627\u064b \u0648\u0641\u0642 \u0627\u0644\u0645\u0631\u0633\u0648\u0645 \u0627\u0644\u0645\u0644\u0643\u064a 26/2023." } },
