            { "@type": "Question", "name": "\u0647\u0644 \u064a\u0645\u0643\u0646 \u0644\u0645\u0633\u0627\u0639\u062f \u0648\u0627\u062a\u0633\u0627\u0628 \u0627\u0644\u0630\u0643\u064a \u0623\u0646 \u064a\u062d\u0644 \u0645\u062d\u0644 \u0645\u0648\u0638\u0641 \u0627\u0644\u0627\u0633\u062a\u0642\u0628\u0627\u0644\u061f", "acceptedAnswer": { "@type": "Answer", "text": "\u0644\u0627. \u0627\u0644\u0646\u0645\u0648\u0630\u062c \u0627\u0644\u0635\u062d\u064a\u062d \u0647\u0648 \u0627\u0644\u0630\u0643\u0627\u0621 \u0627\u0644\u0627\u0635\u0637\u0646\u0627\u0639\u064a \u064a\u062a\u0648\u0644\u0649 \u0627\u0644\u062d\u062c\u0645 \u0628\u064a\u0646\u0645\u0627 \u064a\u062a\u0648\u0644\u0649 \u0627\u0644\u0625\u0646\u0633\u0627\u0646 \u0627\u0644\u0645\u062d\u0627\u062f\u062b\u0627\u062a \u0627\u0644\u062d\u0633\u0627\u0633\u0629." } },
